INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (107, 'it', 'Inception', 'Un ladro specializzato nell''estrarre segreti dai sogni riceve l''incarico opposto: impiantare un''idea nella mente di un bersaglio.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (108, 'it', 'La La Land', 'Una pianista jazz e un attore aspirante si innamorano a Los Angeles, mentre inseguono i propri sogni artistici.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (107, 'en', 'Inception', 'A thief who steals corporate secrets through dream-sharing technology is given the inverse task of planting an idea into a target''s mind.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (108, 'en', 'La La Land', 'A jazz pianist and an aspiring actress fall in love in Los Angeles while pursuing their dreams.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (110, 'it', 'Obsession', 'Dopo aver spezzato il misterioso bastoncino del desiderio per conquistare il cuore della ragazza che ama un romantico senza speranza ottiene esattamente ciò che ha chiesto ma presto scopre che alcuni desideri hanno un prezzo sinistro e pericoloso.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (110, 'en', 'Obsession', 'After breaking the mysterious "One Wish Willow" to win his crush''s heart, a hopeless romantic finds himself getting exactly what he asked for but soon discovers that some desires come at a dark, sinister price.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (111, 'it', 'Oceania', 'No description available');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (111, 'en', 'Moana', 'Teenage Moana answers the Ocean''s call and, for the first time, voyages beyond the reef of her island of Motunui with infamous demigod Maui on an unforgettable journey to restore prosperity to her people.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (112, 'it', 'Toy Story 5', 'Quando Bonnie riceve in regalo un tablet Lilypad e ne diventa ossessionata, per Buzz, Woody, Jessie e il resto della banda, il lavoro si complica enormemente: dovranno affrontare una nuova, temibile minaccia al mondo del gioco.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (112, 'en', 'Toy Story 5', 'When Bonnie receives a Lilypad tablet as a gift and becomes obsessed, Buzz, Woody, Jessie and the rest of the gang''s jobs become exponentially harder when they have to go head to head with the all-new threat to playtime.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (113, 'it', 'Disclosure Day', 'Se scoprissi che non siamo soli, se qualcuno te lo mostrasse, te lo dimostrasse, questo ti spaventerebbe?');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (113, 'en', 'Disclosure Day', 'A cybersecurity expert becomes a whistleblower after uncovering secrets about aliens, putting him on the run from a corporation. Meanwhile, a meteorologist experiencing strange phenomena joins forces with him to prove there''s life beyond our understanding.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (114, 'it', 'Backrooms', 'Se non fai attenzione e superi la barriera della realtà, entrerai nelle backrooms. Se finisci lì dentro, resta vigile, perché i passi che echeggiano in quelle stanze potrebbero non essere solo i tuoi…');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (114, 'en', 'Backrooms', 'A strange doorway appears in the basement of a furniture showroom.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (115, 'it', 'Odissea', 'Ulisse, il leggendario re greco di Itaca, intraprende un lungo e pericoloso viaggio verso casa dopo la guerra di Troia, raccontando i suoi incontri con esseri mitici come il ciclope Polifemo, le Sirene e la dea strega Circe.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (115, 'en', 'The Odyssey', 'Odysseus, the legendary King of Ithaca, embarks on a long and perilous journey home following the Trojan War. Throughout his voyage, he is forced to confront the whims of gods, mythological monsters, and trials that stretch both his cunning and his humanity to the breaking point.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (116, 'it', 'Scary Movie', 'Ventisei anni dopo essere sfuggiti a un killer mascherato fin troppo familiare, i Core Four tornano nel mirino dell’assassino — e nessun franchise horror è al sicuro.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (116, 'en', 'Scary Movie', 'Twenty-six years after outrunning a suspiciously familiar masked killer, the Core Four are back in the killer''s crosshairs and no horror movie IP is safe.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (117, 'it', 'Passenger', 'Dopo aver assistito a un raccapricciante incidente sull’autostrada, una giovane coppia riparte convinta di essersi lasciata tutto alle spalle. Ma qualcosa è salito a bordo con loro. Una presenza demoniaca, si annida nell’ombra, silenziosa e inesorabile. Non si fermerà finché non li avrà presi entrambi, trasformando il loro viaggio on the road in una discesa senza ritorno nell’incubo.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (117, 'en', 'Passenger', 'After a young couple witnesses a gruesome highway accident, they soon realize they did not leave the crash scene alone, as a demonic presence called the Passenger that won''t stop until it claims them both turns their van life adventure into a nightmare.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (118, 'it', 'The Furious', 'Dopo che la figlia di Wang Wei viene rapita da una rete criminale e lui non riceve alcun aiuto dalla polizia corrotta, Wei si mette alla sua ricerca. Il suo unico alleato è Navin, un''implacabile giornalista la cui moglie è misteriosamente scomparsa. Animati da una furiosa sete di vendetta, l''improbabile duo combatte senza pietà contro i rapitori in questo esplosivo scontro di arti marziali.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (118, 'en', 'The Furious', 'After a criminal network kidnaps Wang Wei''s daughter and the corrupt police refuse to assist him, Wei sets out on his own to locate her. Navin, a tenacious journalist whose wife has mysteriously vanished, is his only ally. In this explosive martial arts showdown, the unlikely duo fights the kidnappers ruthlessly driven by a furious vengeance.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (119, 'it', 'Il diavolo veste Prada 2', 'Andy Sachs torna a Runway mentre Miranda Priestly naviga in un nuovo panorama mediatico mantenendo la sua posizione in Runway. Entrambe riallacciano i contatti con l''ex assistente Emily Charlton, ora a capo di un marchio di lusso con finanziamenti che potrebbero garantire la sopravvivenza di Runway.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (119, 'en', 'The Devil Wears Prada 2', 'Andy Sachs returns to Runway as Miranda Priestly navigates a new media landscape and Runway''s position within. The duo reconnect with former assistant Emily Charlton, now the head of a luxury brand that possesses funding which could ensure Runway''s survival.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (120, 'it', 'Твоё сердце будет разбито', NULL);
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (120, 'en', 'Your Heart Will Be Broken', 'High school student Polina is saved from bullying at her new school and makes a deal with the main bully Bars: he must pretend to be her boyfriend and protect her, and she must do everything he says. During this game, the couple develops real feelings, but her family and classmates have reasons to separate the lovers.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (121, 'it', 'Supergirl', 'Quando un avversario inaspettato e spietato colpisce troppo vicino a casa, Kara Zor-El, alias Supergirl, è costretta a stringere un’improbabile alleanza intraprendendo un’epica avventura interstellare all’insegna della vendetta e della giustizia.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (121, 'en', 'Supergirl', 'When an unexpected and ruthless adversary strikes too close to home, Kara Zor-El, aka Supergirl, reluctantly joins forces with an unlikely companion on an epic, interstellar journey of vengeance and justice.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (122, 'it', 'Minions & Monsters', 'Questa è la storia turbolenta, assurda e assolutamente vera di come i Minions abbiano conquistato Hollywood, siano diventati star del cinema, abbiano perso tutto, abbiano liberato dei mostri nel mondo e poi si siano riuniti per cercare di salvare il pianeta dal caos che loro stessi avevano creato.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (122, 'en', 'Minions & Monsters', 'This is the rambunctious, ridiculous and totally true story of how the Minions conquered Hollywood, became movie stars, lost everything, unleashed monsters onto the world and then banded together to try and save the planet from the mayhem they had just created.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (123, 'it', 'L''ultima missione: Project Hail Mary', 'L’insegnante di scienze Ryland Grace (Ryan Gosling) si sveglia su un’astronave lontano da casa anni luce e senza alcun ricordo di chi sia o di come sia arrivato lì. Con il riaffiorare della sua memoria, torna alla luce lo scopo della sua missione: risolvere l’enigma della misteriosa sostanza che sta causando il collasso del Sole. Dovrà fare affidamento sia sulle sue conoscenze scientifiche che sulle sue capacità di pensare fuori dagli schemi per salvare dall’estinzione la vita sulla Terra… ma un''inaspettata amicizia gli farà capire che non è solo in questa impresa.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (123, 'en', 'Project Hail Mary', 'Science teacher Ryland Grace wakes up on a spaceship light years from home with no recollection of who he is or how he got there. As his memory returns, he begins to uncover his mission: solve the riddle of the mysterious substance causing the sun to die out. He must call on his scientific knowledge and unorthodox ideas to save everything on Earth from extinction.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (124, 'it', 'Citizen Vigilante', 'Sanders è frustrato dalla mancanza di giustizia pubblica e decide di prendere in mano la situazione diventando un vigilante. Si propone di punire sia i criminali che i funzionari corrotti. Man mano che la sua attività di vigilante aumenta, cresce anche la sua notorietà, conquistando il sostegno della gente come figura eroica, nonché l''attenzione di Henry, un capo dell''Interpol, che lo vede come una minaccia per la società.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (124, 'en', 'Citizen Vigilante', 'A man takes justice into his own hands, hunting down criminals. His vigilante crusade makes him a social media star but puts him at odds with the local police chief.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (125, 'it', 'Michael', 'Il film racconta la vita di Michael Jackson oltre la musica, tracciando il suo viaggio dalla scoperta del suo straordinario talento come protagonista dei Jackson Five, all''artista visionario la cui ambizione creativa ha alimentato un''incessante ricerca per diventare il più grande intrattenitore del mondo. Evidenziando sia la sua vita fuori dal palco che alcune delle performance più iconiche degli inizi della sua carriera da solista, il film offre al pubblico un posto in prima fila a Michael Jackson come mai prima d''ora. È qui che inizia la sua storia.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (125, 'en', 'Michael', 'The story of Michael Jackson, one of the most influential artists the world has ever known, and his life beyond the music. His journey from the discovery of his extraordinary talent as the lead of the Jackson Five, to the visionary artist whose creative ambition fueled a relentless pursuit to become the biggest entertainer in the world, highlighting both his life off-stage and some of the most iconic performances from his early solo career.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (126, 'it', 'Deep Water - Incubo degli abissi', 'Un gruppo di passeggeri internazionali a bordo di un volo da Los Angeles a Shanghai è costretto a effettuare un atterraggio di emergenza in acque infestate da squali. Il gruppo, terrorizzato, è costretto a collaborare e a superare le proprie divergenze se vuole salvarsi dall''aereo che affonda e dalla furia degli squali attratti dal relitto.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (126, 'en', 'Deep Water', 'A group of international passengers on a flight from Los Angeles to Shanghai is forced to make an emergency landing in shark-infested waters. The terrified group is forced to work together and overcome their differences if they hope to escape their sinking plane and the frenzy of sharks drawn to the wreckage.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (127, 'it', 'Mortal Kombat II', 'Mortal Kombat 2, il film diretto da Simon McQuoid, è il sequel del film del 2021 tratto dall''omonima saga di videogiochi. Il protagonista Johnny Cage è interpretato da Karl Urban. Questa volta, i campioni più amati dai fan – ora affiancati da Johnny Cage in persona – si affrontano in un’epica battaglia all''ultimo sangue per fermare il dominio oscuro di Shao Kahn, una minaccia che incombe sull’esistenza stessa del Regno della Terra e dei suoi difensori.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (127, 'en', 'Mortal Kombat II', 'The fan favorite champions—now joined by Johnny Cage himself—are pitted against one another in the ultimate, no-holds barred, gory battle to defeat the dark rule of Shao Kahn that threatens the very existence of the Earthrealm and its defenders.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (128, 'it', 'Avatar: Fuoco e Cenere', 'In seguito alla devastante guerra contro la RDA e alla perdita del loro figlio maggiore, Jake Sully e Neytiri affrontano una nuova minaccia su Pandora: il Popolo della Cenere, una tribù Na''vi violenta e assetata di potere guidata dagli spietati Varang. La famiglia di Jake deve lottare per la propria sopravvivenza e per il futuro di Pandora in un conflitto che li spinge ai loro limiti emotivi e fisici.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (128, 'en', 'Avatar: Fire and Ash', 'In the wake of the devastating war against the RDA and the loss of their eldest son, Jake Sully and Neytiri face a new threat on Pandora: the Ash People, a violent and power-hungry Na''vi tribe led by the ruthless Varang. Jake''s family must fight for their survival and the future of Pandora in a conflict that pushes them to their emotional and physical limits.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (129, 'it', 'Super Mario Galaxy Il Film', 'Mario e Luigi, i gemelli idraulici, applicano il loro motto "Let''s-a-go" per risolvere i problemi di ogni giorno nella loro nuova casa del Regno dei Funghi. Mentre sono impegnati ad aiutare la Principessa Peach e a riportare sulla retta via Bowser, rimpicciolito e imprigionato, incontrano un nuovo compagno: Yoshi. La festa di compleanno della Principessa Peach dà luogo a un''avventura galattica, che vede i due fratelli lanciarsi nello spazio per fermare i loschi piani di Bowser Jr. e salvare la principessa Rosalinda.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (129, 'en', 'The Super Mario Galaxy Movie', 'Having thwarted Bowser''s previous plot to marry Princess Peach, Mario and Luigi now face a fresh threat in Bowser Jr., who is determined to liberate his father from captivity and restore the family legacy. Alongside companions new and old, the brothers travel across the stars to stop the young heir''s crusade.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (130, 'it', 'Swapped - Al tuo posto', 'Una piccola creatura del bosco e un maestoso uccello si scambiano improvvisamente di corpo e devono fare squadra per sopravvivere all''avventura più folle della loro vita.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (130, 'en', 'Swapped', 'A small woodland creature and a majestic bird, two natural sworn enemies of the Valley, magically trade places and set off on an adventure of a lifetime to switch back. Their journey soon uncovers a greater threat—one that could endanger not only their species, but the entire valley they call home.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (131, 'it', 'Jumpers - Un salto tra gli animali', 'Gli scienziati hanno scoperto come far “saltare” la coscienza umana in animali robotici realistici, permettendo alle persone di comunicare con gli animali, come animali! L''amante degli animali Mabel coglie l''opportunità per usare la tecnologia, svelando misteri nel mondo animale oltre qualsiasi cosa potesse immaginare.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (131, 'en', 'Hoppers', 'Scientists have discovered how to ''hop'' human consciousness into lifelike robotic animals, allowing people to communicate with animals as animals. Animal lover Mabel seizes an opportunity to use the technology, uncovering mysteries within the animal world beyond anything she could have imagined.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (132, 'it', 'Lee Cronin - La Mummia', 'La giovane figlia di un giornalista scompare nel deserto senza lasciare traccia. Otto anni dopo, la famiglia, ancora devastata dal dolore, viene sconvolta dal suo improvviso ritorno: quello che dovrebbe essere un ricongiungimento gioioso si trasforma rapidamente in un incubo a occhi aperti.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (132, 'en', 'Lee Cronin''s The Mummy', 'The young daughter of a journalist disappears into the desert without a trace—eight years later, the broken family is shocked when she is returned to them, as what should be a joyful reunion turns into a living nightmare.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (133, 'it', 'Il danno', 'Politico inglese, leader del partito conservatore, incontra casualmente Anna, la ragazza di suo figlio, e sale sul treno rapido della passione che porta alla distruzione di una famiglia.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (133, 'en', 'Damage', 'The life of a respected British politician at the height of his career crumbles when he becomes obsessed with his son''s lover.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (134, 'it', 'Apex', 'Durante un''avventura solitaria nella natura selvaggia australiana, una donna in lutto si ritrova coinvolta in un gioco perverso e diventa la preda di un assassino astuto.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (134, 'en', 'Apex', 'A grieving woman pushing her limits on a solo adventure in the Australian wild is ensnared in a twisted game with a cunning killer who thinks she''s prey.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (135, 'it', 'Little Brother', 'La vita impeccabile di un agente immobiliare rigido e controllato è sconvolta dall''improvvisa ricomparsa del caotico e adorabile "fratello minore".');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (135, 'en', 'Little Brother', 'A tightly wound realtor''s picture-perfect life gets an extreme makeover when his lovably chaotic "little brother" suddenly reappears.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (136, 'it', 'Tom Clancy''s Jack Ryan - Ghost War', 'Jack Ryan è riluttante a tornare nel mondo dello spionaggio quando una missione internazionale sotto copertura svela una cospirazione mortale. Con il tempo che stringe, si unisce agli alleati della CIA Mike November e James Greer e all''acuta ufficiale dell''MI6 Emma Marlowe per combattere un''unità operativa segreta fuori controllo in uno scontro ad alto rischio e profondamente personale.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (136, 'en', 'Tom Clancy''s Jack Ryan: Ghost War', 'Jack Ryan is reluctantly pulled back into espionage when an international covert mission unravels a deadly conspiracy. Racing against time, he joins CIA allies Mike November & James Greer and sharp MI6 officer Emma Marlowe to battle a rogue black-ops unit in a high-stakes, deeply personal fight.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (137, 'it', 'The Mandalorian and Grogu', 'L’Impero è caduto e i signori della guerra imperiali sono ancora sparsi per la galassia. Mentre lanascente Nuova Repubblica cerca di proteggere tuRo ciò per cui l’Alleanza Ribelle ha combaRuto, haarruolato l’aiuto del leggendario cacciatore di taglie mandaloriano Din Djarin (Pedro Pascal) e delsuo giovane apprendista Grogu. DireRo da Jon Favreau, Star Wars: The Mandalorian and Grogu vedeanche la partecipazione di Sigourney Weaver ed è prodoRo da Jon Favreau, Kathleen Kennedy, DaveFiloni e Ian Bryce, con musiche composte da Ludwig Göransson');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (137, 'en', 'The Mandalorian and Grogu', 'The evil Empire has fallen, and Imperial warlords remain scattered throughout the galaxy. As the fledgling New Republic works to protect everything the Rebellion fought for, they have enlisted the help of legendary Mandalorian bounty hunter Din Djarin and his young apprentice Grogu.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (138, 'it', 'Demon Slayer: Il Castello dell''Infinito - Parte 1', 'Tanjiro Kamado è un ragazzo unitosi a un’organizzazione dedita alla caccia dei demoni chiamata Squadra dei cacciatori di demoni dopo che la sorella minore Nezuko è diventata una di questi mostri. Acquisendo sempre più forza e approfondendo i legami di amicizia con i suoi compagni, Tanjiro ha combattuto molti demoni con i suoi compagni Zenitsu Agatsuma e Inosuke Hashibira. Con il capo della Squadra dei cacciatori di demoni in pericolo, Tanjiro e i Pilastri accorrono al quartier generale, dove però per mano di Muzan Kibutsuji precipitano in un luogo misterioso. Lo spazio in cui Tanjiro e la Squadra dei cacciatori di demoni sono piombati è la fortezza dei demoni: il Castello dell''Infinito. Il campo di battaglia è pronto e lo scontro finale tra la Squadra dei cacciatori di demoni e i demoni si accende.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (138, 'en', 'Demon Slayer: Kimetsu no Yaiba Infinity Castle', 'The Demon Slayer Corps are drawn into the Infinity Castle, where Tanjiro, Nezuko, and the Hashira face terrifying Upper Rank demons in a desperate fight as the final battle against Muzan Kibutsuji begins.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (139, 'it', 'Pecore sotto copertura', 'George (Hugh Jackman) è un pastore che ogni sera legge romanzi gialli alle sue amate pecore, convinto che non possano comprenderlo. Quando però un misterioso incidente sconvolge la tranquillità della fattoria, le pecore decidono di dover diventare loro stesse delle detective. Seguendo gli indizi e indagando sui sospetti umani, dimostrano che anche le pecore possono essere brillanti investigatrici.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (139, 'en', 'The Sheep Detectives', 'George Hardy is a shepherd who reads detective novels to his beloved sheep every night, assuming they can''t possibly understand. But when a mysterious incident disrupts life on the farm, the sheep realize they must become the detectives. As they follow the clues and investigate human suspects, they prove that even sheep can be brilliant crime-solvers.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (140, 'it', 'The Punisher: One Last Kill', 'Frank Castle è un uomo tormentato dal disturbo post-traumatico e dai fantasmi del passato dopo aver compiuto la sua vendetta. Quando la spietata boss mafiosa Ma Gnucci mette una taglia sulla sua testa, scatenando il caos dei criminali a New York, Frank deve combattere un''ultima volta per proteggere gli innocenti e ritrovare il suo scopo.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (140, 'en', 'The Punisher: One Last Kill', 'As Frank Castle searches for meaning beyond revenge, an unexpected force pulls him back into the fight.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (141, 'it', 'Boulevard', 'Una nuova città, una nuova vita e un incontro inatteso con Luke, un ragazzo vitale e tormentato. Nonostante gli avvertimenti, Hasley non riesce a stargli lontana. Nel loro "boulevard" scoprono un amore autentico e liberatorio. Ma mentre il passato di lui minaccia di distruggerli entrambi, Hasley si trova di fronte a una scelta straziante: si può salvare qualcuno che non è pronto a essere salvato?');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (141, 'en', 'Boulevard', 'New city, new life, and an unexpected encounter with Luke-a boy fueled by adrenaline and haunted by demons. Despite the warnings, Hasley can''t stay away. In their ''boulevard,'' they find a raw, liberating love. But as his past threatens to destroy them both, Hasley faces a heartbreaking choice: can you save someone who isn''t ready to be rescued?');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (142, 'it', 'Kraken', 'La biologa marina Johanne sta facendo ricerche in un allevamento ittico a Vangsnes, una comunità rurale situata vicino al fiordo, quando incontra diversi strani eventi. Insieme alla morte brutale di due adolescenti locali, tutti i segni indicano il fiordo profondo; può esserci di più in profondità di quanto l''occhio possa vedere? In fondo al fiordo più profondo riposa un mostro mitico grande come una montagna, con una miriade di braccia pronte a schiacciare e divorare qualsiasi cosa riescano ad afferrare.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (142, 'en', 'Kraken', 'A marine biologist is doing research on a fish farm when she encounters several strange occurrences. Along with the brutal deaths of two teenagers, all signs point to the deep fjord; can there be more to the depths than the eye can see?');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (143, 'it', 'Enola Holmes 3', 'Quest''avventura segue la detective Enola Holmes fino a Malta, dove i preparativi per le sue nozze si scontrano con la scomparsa di Sherlock che la trascina in un caso pericoloso.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (143, 'en', 'Enola Holmes 3', 'Adventure follows detective Enola Holmes to Malta, where her plans to tie the knot unravel when Sherlock''s disappearance plunges her into a perilous case.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (144, 'it', 'Dolly', NULL);
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (144, 'en', 'Dolly', 'Young Macy is abducted by a deranged, monstrous figure who wants to raise her as its child.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (145, 'it', 'Spider-Man: No Way Home', 'In seguito agli eventi di Spider-Man: Far from Home, la vita di Peter Parker viene stravolta dopo che Mysterio rivela al mondo la sua identità. Peter chiede aiuto a Stephen Strange affinché usi la magia per far scordare a tutti la sua identità. Ma l''incantesimo non va come previsto e Peter si ritrova a dover affrontare nemici da altri universi e a scoprire cosa significa davvero essere Spider-Man.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (145, 'en', 'Spider-Man: No Way Home', 'Peter Parker is unmasked and no longer able to separate his normal life from the high-stakes of being a super-hero. When he asks for help from Doctor Strange the stakes become even more dangerous, forcing him to discover what it truly means to be Spider-Man.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (146, 'it', 'Vixen!', 'Vixen è una procace ragazza che vive con il marito pilota Tom, che non si accorge dell''infedeltà della moglie. Quando una giovane coppia chiede ospitalità nella casa dei coniugi, Vixen inizierà subito a sedurre entrambi. Le voglie di Vixen si dipanano nell''opera prima del genio dell''erotismo Russ Meyer.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (146, 'en', 'Vixen!', 'In a Canadian mountain resort, Vixen Palmer resides with her naive pilot husband Tom. While he''s away flying in tourists, she sleeps with practically everybody including a husband and his wife, and even her biker brother. However, the only one she won''t bed is her brother''s friend... who is Black.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (147, 'it', 'Una di famiglia - The Housemaid', 'La trama segue Millie, una donna che cerca un nuovo inizio e trova lavoro come domestica per una coppia benestante ed elitaria. Ma come spesso accade nei thriller, le apparenze ingannano. Millie scoprirà presto che dietro la facciata di questa ricca famiglia perfetta si nascondono segreti oscuri e pericolosi.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (147, 'en', 'The Housemaid', 'Trying to escape her past, Millie Calloway accepts a job as a live-in housemaid for the wealthy Nina and Andrew Winchester. But what begins as a dream job quickly unravels into something far more dangerous—a sexy, seductive game of secrets, scandal, and power.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (148, 'it', 'È colpa tua: Londra', 'Nick e Noah stanno per intraprendere avventure che cambieranno per sempre le loro vite e che rischiano di separarli: Nick è impegnato negli affari con il padre, mentre Noah inizia un nuovo capitolo all''Università di Oxford. Vivendo vite separate e incontrando nuove persone, si ritrovano invischiati in tentazioni, rivalità e tradimenti, e il loro legame viene messo alla prova come mai prima d''ora. Mentre i segreti vengono a galla e le tentazioni si fanno sempre più forti, dovranno lottare per restare uniti, o rischieranno di perdere tutto.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (148, 'en', 'Your Fault: London', 'Nick and Noah are both embarking on life-changing adventures that are threatening to pull them apart—Nick in business with his father and Noah starting a fresh chapter at Oxford University. Now living separate lives, and meeting new people, they find themselves entangled in temptations, rivalries, and betrayals and their bond is tested like never before. As secrets unravel and temptation rises, they must fight to hold onto each other—or risk losing everything.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (149, 'it', 'Interstellar', 'In seguito alla scoperta di un cunicolo spazio-temporale, un gruppo di esploratori si avventura in una eroica missione per tentare di superare i limiti della conquista spaziale e oltrepassare le distanze che fino a quel momento avevano reso impraticabili i viaggi interstellari. L''obiettivo è quello di trovare nuovi luoghi dove coltivare il granoturco, l''unica coltivazione rimasta dopo un drastico cambiamento climatico che ha colpito soprattutto l''agricoltura.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (149, 'en', 'Interstellar', 'The adventures of a group of explorers who make use of a newly discovered wormhole to surpass the limitations on human space travel and conquer the vast distances involved in an interstellar voyage.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (150, 'it', 'Missione Shelter', 'Un uomo che vive in esilio autoimposto su un''isola remota salva una giovane ragazza da una violenta tempesta, innescando una catena di eventi che lo costringeranno a uscire dall''isolamento per proteggerla dai nemici legati al suo passato.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (150, 'en', 'Shelter', 'A man living in self-imposed exile on a remote island rescues a young girl from a violent storm, setting off a chain of events that forces him out of seclusion to protect her from enemies tied to his past.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (151, 'it', 'In the Grey', 'Una squadra segreta di agenti speciali capaci di muoversi abilmente nella “zona grigia” tra potere, denaro e violenza, deve recuperare una fortuna da un miliardo di dollari. Quando il piano devia improvvisamente dal percorso previsto, la missione si trasforma in una corsa senza regole, dove ogni alleanza è fragile e ogni scelta può essere fatale.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (151, 'en', 'In the Grey', 'A covert team of elite operatives are living in the shadows. When a ruthless despot steals a billion-dollar fortune, they''re sent to take it back—an impossible heist that erupts into a deadly game of strategy, deception and survival.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (152, 'it', 'Zootropolis 2', 'Dopo aver risolto il caso più importante nella storia di Zootropolis, i poliziotti alle prime armi Judy Hopps e Nick Wilde scoprono che la loro collaborazione non è così solida come pensavano quando il capo Bogo ordina loro di unirsi al programma di consulenza "Partners in Crisis". Ma non ci vuole molto perché la loro collaborazione venga messa a dura prova quando si ritrovano sulle tracce tortuose di un mistero legato all''arrivo di un serpente velenoso nella metropoli degli animali.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (152, 'en', 'Zootopia 2', 'After cracking the biggest case in Zootopia''s history, rookie cops Judy Hopps and Nick Wilde find themselves on the twisting trail of a great mystery when Gary De''Snake arrives and turns the animal metropolis upside down. To crack the case, Judy and Nick must go undercover to unexpected new parts of town, where their growing partnership is tested like never before.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (153, 'it', 'GOAT - Sogna in grande', 'Will, una piccola capra con grandi sogni, all’improvviso ha l’occasione di entrare nella lega professionistica di “pallaruggente”, uno sport ad alto tasso di adrenalina, dominato dagli animali più veloci e feroci del pianeta. I suoi nuovi compagni non sono esattamente entusiasti all’idea di avere una capretta in squadra, ma Will è deciso a cambiare le regole del gioco e dimostrare, una volta per tutte, che anche i “piccoli” sanno lasciare il segno.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (153, 'en', 'GOAT', 'A small goat with big dreams gets a once-in-a-lifetime shot to join the pros and play roarball, a high-intensity, co-ed, full-contact sport dominated by the fastest, fiercest animals in the world.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (154, 'it', 'Oceania 2', 'A tre anni dal suo primo viaggio, Vaiana è impegnata in un lungo viaggio alla ricerca di persone oltre le coste di Motunui. Assieme a Maui e a un nuovissimo equipaggio di improbabili marittimi, Vaiana si imbarca alla volta dei lontani mari dell''Oceania in acque pericolose per un''avventura diversa da qualsiasi cosa abbia mai affrontato.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (154, 'en', 'Moana 2', 'After receiving an unexpected call from her wayfinding ancestors, Moana journeys alongside Maui and a new crew to the far seas of Oceania and into dangerous, long-lost waters for an adventure unlike anything she''s ever faced.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (155, 'it', 'Predator: Badlands', 'Nel futuro, su un pianeta remoto, un giovane Predatore, emarginato dal suo clan, trova un alleato improbabile in Thia e intraprende un viaggio pericoloso alla ricerca del nemico supremo.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (155, 'en', 'Predator: Badlands', 'Cast out from his clan, a young Predator finds an unlikely ally in a damaged android and embarks on a treacherous journey in search of the ultimate adversary.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (156, 'it', 'Send Help', 'Due colleghi un tempo rivali si ritrovano improvvisamente naufraghi su un''isola deserta dopo essere gli unici sopravvissuti a un disastro aereo. Costretti a collaborare per sopravvivere, Linda e Bradley dovranno affrontare vecchi rancori e mettere alla prova la propria forza di volontà per riuscire a salvarsi.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (156, 'en', 'Send Help', 'Two colleagues become stranded on a deserted island, the only survivors of a plane crash. On the island, they must overcome past grievances and work together to survive, but ultimately, it''s a battle of wills and wits to make it out alive.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (157, 'it', 'Guardia del corpo', 'Frank Farmer, ex agente segreto viene ingaggiato come guardia del corpo personale della pop star Rachel Marron, la cui vita privata è protetta con misure di sicurezza elevatissime, perchè c''è qualcuno che la perseguita...');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (157, 'en', 'The Bodyguard', 'A former Secret Service agent grudgingly takes an assignment to protect a pop idol who''s threatened by a crazed fan. At first, the safety-obsessed bodyguard and the self-indulgent diva totally clash. But before long, all that tension sparks fireworks of another sort, and the love-averse tough guy is torn between duty and romance.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (158, 'it', 'La casa - Il risveglio del male', 'Una stanca Beth fa una visita tardiva a sua sorella maggiore Ellie, che sta crescendo tre figli da sola in un angusto appartamento di Los Angeles. La riunione delle sorelle è interrotta dalla scoperta di un libro misterioso nelle viscere dell’edificio di Ellie, che dà origine a demoni indemoniati e spinge Beth in una battaglia primordiale per la sopravvivenza mentre deve affrontare una versione da incubo della maternità.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (158, 'en', 'Evil Dead Rise', 'A reunion between two estranged sisters gets cut short by the rise of flesh-possessing demons, thrusting them into a primal battle for survival as they face the most nightmarish version of family imaginable.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (159, 'it', 'È colpa mia?', 'Noah deve lasciare la sua città, il fidanzato e gli amici per trasferirsi nella villa di William Leister, il nuovo ricco marito di sua madre Rafaela. D''altra parte, 17 anni, orgogliosa e indipendente, Noah resiste a vivere in una villa circondata dal lusso. Lì incontra Nick, il suo nuovo fratellastro, e lo scontro tra le loro forti personalità diventa evidente fin dal primo momento.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (159, 'en', 'My Fault', 'Noah must leave her city, boyfriend, and friends to move into William Leister''s mansion, the flashy and wealthy husband of her mother Rafaela. As a proud and independent 17 year old, Noah resists living in a mansion surrounded by luxury. However, it is there where she meets Nick, her new stepbrother, and the clash of their strong personalities becomes evident from the very beginning.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (160, 'it', 'Toy Story - Il mondo dei giocattoli', 'Guidati da Woody, i giocattoli di Andy vivono felici nella sua stanza fino al compleanno di Andy che porta Buzz Lightyear sulla scena. Temendo di perdere il suo posto nel cuore di Andy, Woody trama contro Buzz. Ma quando le circostanze separano Buzz e Woody dal loro proprietario, la coppia alla fine impara a mettere da parte le loro differenze.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (160, 'en', 'Toy Story', 'Led by Woody, Andy''s toys live happily in his room until Andy''s birthday brings Buzz Lightyear onto the scene. Afraid of losing his place in Andy''s heart, Woody plots against Buzz. But when circumstances separate Buzz and Woody from their owner, the duo eventually learns to put aside their differences.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (161, 'it', 'Super Mario Bros. Il Film', 'Un idraulico di Brooklyn di nome Mario viaggia attraverso il Regno dei Funghi con una principessa di nome Peach e un fungo antropomorfo di nome Toad per trovare il fratello di Mario, Luigi, e salvare il mondo da uno spietato mostro sputafuoco di nome Bowser.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (161, 'en', 'The Super Mario Bros. Movie', 'While working underground to fix a water main, Brooklyn plumbers—and brothers—Mario and Luigi are transported down a mysterious pipe and wander into a magical new world. But when the brothers are separated, Mario embarks on an epic quest to find Luigi.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (162, 'it', 'Dune', 'In un distante futuro dell''umanità, il duca Leto Atreides accetta la gestione del pericoloso pianeta di Arrakis, anche noto come Dune, l''unica fonte della sostanza più preziosa dell''universo, "la spezia", una droga che allunga la vita, fornisce capacità mentali sovrumane e rende possibili i viaggi nello spazio. Nonostante Leto sappia che l''offerta è parte di una complessa trappola creata dai suoi nemici, decide di partire per Arrakis, portando con sé la sua concubina Bene Gesserit Lady Jessica, il giovane figlio ed erede Paul, e i suoi più fidati consiglieri. Leto prende il controllo di un''operazione di estrazione della spezia, resa pericolosa dalla presenza di enormi vermi delle sabbie. Un amaro tradimento conduce Paul e Jessica dai Fremen, nativi di Arrakis che vivono nel deserto più profondo.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (162, 'en', 'Dune', 'Paul Atreides, a brilliant and gifted young man born into a great destiny beyond his understanding, must travel to the most dangerous planet in the universe to ensure the future of his family and his people. As malevolent forces explode into conflict over the planet''s exclusive supply of the most precious resource in existence - a commodity capable of unlocking humanity''s greatest potential - only those who can conquer their fear will survive.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (163, 'it', 'Toy Story 4', 'Woody è sempre stato sicuro del suo posto nel mondo, devoto a prendersi cura di suo figlio, che si tratti di Andy o Bonnie. Ma dopo che Bonnie crea un nuovo giocattolo riluttante chiamato "Forky", un''avventura in viaggio insieme a vecchi e nuovi amici mette in discussione tutto ciò in cui Woody crede riguardo alla lealtà, allo scopo e a cosa significhi davvero essere un giocattolo.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (163, 'en', 'Toy Story 4', 'Woody has always been confident about his place in the world, devoted to taking care of his kid—whether that''s Andy or Bonnie. But after Bonnie creates a reluctant new toy called "Forky", a road trip adventure alongside old and new friends challenges everything Woody believes about loyalty, purpose, and what it truly means to be a toy.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (164, 'it', 'Ne Zha - L''ascesa del guerriero di fuoco', 'Ne Zha, un giovane ribelle dai poteri sovrannaturali, stringe un’alleanza instabile con il principe dei draghi, Ao Bing, in una battaglia epica per proteggere i loro rispettivi clan. Ma dopo lo scontro, i loro corpi sono sull’orlo della distruzione. Ne Zha deve così intraprendere una pericolosa missione alla ricerca di un elisir capace di salvare il corpo di Ao Bing. Durante questo viaggio tra mostri epici e leggende, Ne Zha scoprirà una cospirazione che minaccia di scatenare una guerra devastante tra il bene e il male — e dovrà affrontare forze oscure e inganni per proteggere ciò che ha di più caro.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (164, 'en', 'Ne Zha 2', 'After a catastrophic event leaves their bodies destroyed, Ne Zha and Ao Bing are granted a fragile second chance at life. As tensions rise between the dragon clans and celestial forces, the two must undergo a series of perilous trials that will test their bond, challenge their identities, and decide the fate of both mortals and immortals.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (165, 'it', 'Greenland 2: Migration', 'Avendo trovato la sicurezza del bunker della Groenlandia dopo che la cometa Clarke ha decimato la Terra, la famiglia Garrity deve ora rischiare tutto per intraprendere un pericoloso viaggio attraverso la terra desolata d''Europa per trovare una nuova casa.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (165, 'en', 'Greenland 2: Migration', 'Having found the safety of the Greenland bunker after the comet Clarke decimated the Earth, the Garrity family must now risk everything to embark on a perilous journey across the wasteland of Europe to find a new home.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (166, 'it', 'Avengers: Infinity War', 'Dalla nascita dell''universo, sei gemme elementari rappresentano i vari aspetti fondamentali del cosmo e chi le possedesse tutte raggiungerebbe l''onnipotenza. È questo l''obiettivo di Thanos, il titano pazzo che ritiene se stesso come un correttivo alla sovrappopolazione universale e pensa di essere una misura necessaria e giusta, persino benevola, mentre agli altri il suo operato appare, correttamente, come una serie di genocidi. Gli Avengers e i Guardiani della Galassia dovranno cercare di fermarlo, ma come se non bastasse la sua inarrestabile potenza ci sono dalla sua armate aliene e quattro letali "figli", ognuno deciso a consegnargli le gemme dell''infinito.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (166, 'en', 'Avengers: Infinity War', 'As the Avengers and their allies have continued to protect the world from threats too large for any one hero to handle, a new danger has emerged from the cosmic shadows: Thanos. A despot of intergalactic infamy, his goal is to collect all six Infinity Stones, artifacts of unimaginable power, and use them to inflict his twisted will on all of reality. Everything the Avengers have fought for has led up to this moment - the fate of Earth and existence itself has never been more uncertain.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (167, 'it', 'Oppenheimer', 'La storia del ruolo di J. Robert Oppenheimer, i cui studi condussero alle scoperte legate alla bomba atomica, con il conseguente utilizzo durante le stragi di Hiroshima e Nagasaki durante la Seconda Guerra Mondiale.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (167, 'en', 'Oppenheimer', 'The story of J. Robert Oppenheimer''s role in the development of the atomic bomb during World War II.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (168, 'it', 'War Machine', 'Durante un''ultima ed estenuante missione dell''addestramento dei Ranger, un geniere deve guidare la sua unità contro una gigantesca macchina assassina proveniente da un altro mondo.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (168, 'en', 'War Machine', 'On one last grueling mission during Army Ranger training, a combat engineer must lead his unit in a fight against a giant otherworldly killing machine.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (169, 'it', 'Quasi amici - Intouchables', 'La vita derelitta di Driss, tra carcere, ricerca di sussidi statali e un rapporto non facile con la famiglia, subisce un''impennata quando, a sorpresa, il miliardario paraplegico Philippe lo sceglie come proprio aiutante personale. Incaricato di stargli sempre accanto per spostarlo, lavarlo, aiutarlo nella fisioterapia e via dicendo Driss non tiene a freno la sua personalità poco austera e contenuta. Diventa così l''elemento perturbatore in un ordine alto borghese fatto di regole e paletti, un portatore sano di vitalità e scurrilità che stringe un legame di sincera amicizia con il suo superiore, cambiandogli in meglio la vita.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (169, 'en', 'The Intouchables', 'A true story of two men who should never have met – a quadriplegic aristocrat who was injured in a paragliding accident and a young man from the projects.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (170, 'it', 'The Drama - Un segreto è per sempre', 'Una coppia, nei giorni che precedono le nozze, attraversa una profonda crisi scaturita da una serie di rivelazioni inaspettate, che smentiscono quello che uno dei due futuri coniugi pensava di sapere dell''altro.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (170, 'en', 'The Drama', 'A happily engaged couple is put to the test when an unexpected turn sends their wedding week off the rails.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (171, 'it', 'Toy Story 2 - Woody & Buzz alla riscossa', 'Andy si dirige verso il Campo Cowboy, lasciando i suoi giocattoli a se stessi. Le cose si intensificano quando un collezionista ossessivo di giocattoli di nome Al McWhiggen, proprietario di Al''s Toy Barn, rapisce Woody. I giocattoli di Andy organizzano una coraggiosa missione di salvataggio, Buzz Lightyear incontra il suo pari e Woody deve decidere dove lui e il suo cuore appartengono davvero.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (171, 'en', 'Toy Story 2', 'Andy heads off to Cowboy Camp, leaving his toys to their own devices. Things shift into high gear when an obsessive toy collector named Al McWhiggen, owner of Al''s Toy Barn kidnaps Woody. Andy''s toys mount a daring rescue mission, Buzz Lightyear meets his match and Woody has to decide where he and his heart truly belong.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (172, 'it', 'The Avengers', 'I supereroi più famosi si riuniscono in una squadra di personaggi Marvel leggendari come Iron Man, l''incredibile Hulk, Thor, Captain America, Occhio di Falco e Vedova Nera. Quando la comparsa di un nemico inatteso minaccia la tranquillità e la sicurezza del mondo, Nick Fury, direttore dell''agenzia internazionale per il mantenimento della pace conosciuta come S.H.I.E.L.D., si trova ad aver bisogno di una squadra che salvi il pianeta dall''orlo del disastro. Inizia così, da un capo all''altro della terra, un audace lavoro di reclutamento. Dopo aver riunito la squadra, Nick Fury e il suo fidato assistente, l''Agente Coulson, dovranno convincere i supereroi a convivere e lavorare insieme, utilizzando i loro incredibili poteri contro il pericoloso Loki che è riuscito ad accedere al Tesseract e ai suoi poteri illimitati.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (172, 'en', 'The Avengers', 'When an unexpected enemy emerges and threatens global safety and security, Nick Fury, director of the international peacekeeping agency known as S.H.I.E.L.D., finds himself in need of a team to pull the world back from the brink of disaster. Spanning the globe, a daring recruitment effort begins!');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (173, 'it', 'Harry Potter e la pietra filosofale', 'Harry Potter vive con gli zii e il cuginetto sin dalla più tenera età dopo la morte dei suoi genitori. I parenti non lo amano per nulla. Harry sta ormai per compiere undici anni e viene guardato male anche per alcune sue capacità ''magiche''. Che sono effettive perché Harry è figlio di maghi e comincia a ricevere lettere, regolarmente sequestrate, portate da gufi. Dovrà giungere il gigantesco Hagrid a recapitargliene personalmente una perché possa apprendere di essere stato ammesso a frequentare la Scuola di Magia e Stregoneria di Hogwarts. Gli zii a questo punto non possono far più nulla e Harry raggiunge la Scuola dove apprende che il suo nome è già noto e dove scoprirà di avere naturali doti magiche.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (173, 'en', 'Harry Potter and the Philosopher''s Stone', 'Harry Potter has lived under the stairs at his aunt and uncle''s house his whole life. But on his 11th birthday, he learns he''s a powerful wizard—with a place waiting for him at the Hogwarts School of Witchcraft and Wizardry. As he learns to harness his newfound powers with the help of the school''s kindly headmaster, Harry uncovers the truth about his parents'' deaths—and about the villain who''s to blame.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (174, 'it', 'Jurassic World - La rinascita', 'Cinque anni dopo gli eventi di "Jurassic World - Il Dominio", l''ecologia del pianeta si è dimostrata in gran parte inospitale per i dinosauri. Quelli rimasti vivono in ambienti equatoriali isolati con climi simili a quelli in cui prosperavano un tempo. Le tre creature più gigantesche di quella biosfera tropicale possiedono la chiave per un farmaco che porterà miracolosi benefici salvavita all''umanità.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (174, 'en', 'Jurassic World Rebirth', 'Five years after the events of Jurassic World Dominion, covert operations expert Zora Bennett is contracted to lead a skilled team on a top-secret mission to secure genetic material from the world''s three most massive dinosaurs. When Zora''s operation intersects with a civilian family whose boating expedition was capsized, they all find themselves stranded on an island where they come face-to-face with a sinister, shocking discovery that''s been hidden from the world for decades.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (175, 'it', 'Un film Minecraft', 'Benvenuti nel mondo di Minecraft, dove la creatività non serve solo a costruire, ma è essenziale per la sopravvivenza! Quattro improvvisati avventurieri – Garrett “The Garbage Man” Garrison (Momoa), Henry (Hansen), Natalie (Myers) e Dawn (Brooks) – sono alle prese con problemi quotidiani quando vengono improvvisamente trascinati, attraverso un misterioso portale, nell’Overworld: un bizzarro paese delle meraviglie cubico dove regna l’immaginazione. Per far ritorno a casa, dovranno imparare a padroneggiare questo mondo (e proteggerlo dalla minaccia di Piglins e Zombie) mentre intraprendono una magica missione affiancati da un esperto e inaspettato ‘costruttore’ del posto, Steve (Black). L’avventura metterà alla prova tutti e cinque, sfidandoli a essere coraggiosi e a ritrovare le qualità che rendono ciascuno di loro unico e creativo… le stesse abilità di cui hanno bisogno per tornare a vivere nel mondo reale.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (175, 'en', 'A Minecraft Movie', 'Four misfits find themselves struggling with ordinary problems when they are suddenly pulled through a mysterious portal into the Overworld: a bizarre, cubic wonderland that thrives on imagination. To get back home, they''ll have to master this world while embarking on a magical quest with an unexpected, expert crafter, Steve.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (176, 'it', 'Messaggi per Isabelle', 'Gli intimi ed esilaranti messaggi vocali che una giovane donna lascia alla sorella defunta sono inoltrati a sua insaputa a uno sconosciuto che si innamora di lei a distanza.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (176, 'en', 'Voicemails for Isabelle', 'A young woman''s hilariously confessional voicemails to her late sister are unknowingly redirected to a stranger, who begins to fall in love from afar.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (177, 'it', 'KPop Demon Hunters', 'Quando non fanno il tutto esaurito negli stadi, le superstar del K-pop Rumi, Mira e Zoey usano i loro poteri segreti per proteggere i fan da minacce soprannaturali.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (177, 'en', 'KPop Demon Hunters', 'When K-pop superstars Rumi, Mira and Zoey aren''t selling out stadiums, they''re using their secret powers to protect their fans from supernatural threats.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (178, 'it', 'Il padrino', 'Anni Quaranta. Come è consuetudine, durante il rinfresco per festeggiare le nozze della figlia Conny con Carlo, il "padrino" don Vito Corleone promette assistenza e protezione a familiari e amici. Invia il figliastro Tom Hagen in California per convincere in ogni modo il produttore Jack Woltz a scritturare il cantante Johnny nel suo prossimo film. Woltz non acconsente. Tom allora lo costringe ad accettare con un "avvertimento": l''uccisione del suo cavallo di razza preferito. Sollozzo, a nome della potente "famiglia" Tartaglia, chiede a Corleone finanziamenti e appoggi per il traffico di droga. Il rifiuto scatena una lotta cruenta tra le due cosche: lo stesso don Vito viene ferito gravemente; il figlio minore Michael lo salva da un secondo attentato. Michael, poi, scavalcando l''irruento fratello Sonny e Tom, temporeggiatore, organizza un incontro con Sollozzo e con il corrotto capitano di polizia McCluskey uccidendoli entrambi.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (178, 'en', 'The Godfather', 'Spanning the years 1945 to 1955, a chronicle of the fictional Italian-American Corleone crime family. When organized crime family patriarch, Vito Corleone barely survives an attempt on his life, his youngest son, Michael steps in to take care of the would-be killers, launching a campaign of bloody revenge.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (179, 'it', 'Il robot selvaggio', 'L''epica avventura segue il viaggio di un robot - l''unità ROZZUM 7134, abbreviato Roz - che dopo un naufragio si ritrova su un''isola disabitata dove dovrà imparare ad adattarsi all’ostile ambiente circostante, costruendo gradualmente relazioni con gli altri animali dell’isola e adottando un''ochetta orfana.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (179, 'en', 'The Wild Robot', 'After a shipwreck, an intelligent robot called Roz is stranded on an uninhabited island. To survive the harsh environment, Roz bonds with the island''s animals and cares for an orphaned baby goose.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (180, 'it', 'Crime 101 - La strada del crimine', 'Davis sta preparando il colpo più ambizioso della sua carriera, quello che spera sia l’ultimo, quando il destino lo porta a incrociare il cammino di Sharon, una cinica assicuratrice con cui è forzatamente costretto a collaborare, e di Orman, un pericoloso rivale con metodi ben più violenti. Mentre il furto multimilionario si avvicina, l’inarrestabile tenente Lubesnik stringe il cerchio, intensificando la tensione e assottigliando sempre più il confine tra cacciatore e preda. Ogni protagonista dovrà fare i conti con le conseguenze delle proprie scelte, consapevole di aver superato il punto di non ritorno.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (180, 'en', 'Crime 101', 'When an elusive thief whose high-stakes heists unfold along the iconic 101 freeway in Los Angeles eyes the score of a lifetime, with hopes of this being his final job, his path collides with a disillusioned insurance broker who is facing her own crossroads. Determined to crack the case, a relentless detective closes in on the operation, raising the stakes even higher.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (181, 'it', 'Normal', NULL);
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (181, 'en', 'Normal', 'An unassuming substitute sheriff with a troubled past responds to a bank robbery in a small, sleepy town and unknowingly uncovers something far more explosive.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (182, 'it', 'Coraline e la porta magica', 'Coraline ha undici anni e si è da poco trasferita con la sua famiglia in una nuova casa. Tutto è ancora da esplorare, ma i suoi genitori sono troppo occupati con il lavoro per dedicarsi a lei. La spediscono a giocare in giardino, le preparano al volo la cena quando è ora, la invitano a cavarsela da sola. È così che Coraline scopre una porticina che dà su un tunnel polveroso che porta ad un altro appartamento, in tutto simile al suo, dove vivono un''altra mamma e un altro papà, che altro non fanno che occuparsi di lei. Tutto è spettacolare e desiderabile, dall''altra parte del tunnel, se non fosse che le persone hanno strani bottoni cuciti al posto degli occhi.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (182, 'en', 'Coraline', 'Wandering her rambling old house in her boring new town, 11-year-old Coraline discovers a hidden door to a strangely idealized version of her life. In order to stay in the fantasy, she must make a frighteningly real sacrifice.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (183, 'it', 'Masters of the Universe', 'Dopo essere stati separati per 15 anni, la Spada del Potere conduce il Principe Adam di ritorno su Eternia, dove scopre la sua casa devastata dal diabolico dominio di Skeletor. Per salvare la sua famiglia e il suo mondo, Adam deve unire le forze con i suoi alleati più fidati, Teela e Duncan/Man-At-Arms, e abbracciare il suo vero destino come He-Man, l’uomo più potente dell’universo.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (183, 'en', 'Masters of the Universe', 'After being separated for 15 years, the Sword of Power leads Prince Adam back to Eternia, where he discovers his home shattered under the fiendish rule of Skeletor. To save his family and his world, Adam must join forces with his closest allies, Teela and Duncan/Man-At-Arms, and embrace his true destiny as He-Man — the most powerful man in the universe.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (184, 'it', 'Avatar: La via dell''acqua', 'Jake vive felicemente la sua vita insieme a Neytiri ma Pandora nasconde ancora numerosi misteri. Quando una vecchia, familiare minaccia torna ad affacciarsi per terminare quel che era stato iniziato un tempo, Jake dovrà nuovamente collaborare con l''esercito dei Na''vi per proteggere il loro incredibile pianeta. In veste di patriarca si ritroverà a dover combattere una dura guerra contro gli umani. Jake e Neytiri saranno pertanto costretti a lasciare la loro casa ed esplorare varie regioni di Pandora...');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (184, 'en', 'Avatar: The Way of Water', 'Set more than a decade after the events of the first film, learn the story of the Sully family (Jake, Neytiri, and their kids), the trouble that follows them, the lengths they go to keep each other safe, the battles they fight to stay alive, and the tragedies they endure.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (185, 'it', 'Spider-Man - Un nuovo universo', 'Miles Morales è un ragazzo afro-ispanico di New York che è appena entrato in una scuola relativamente esclusiva, dove però si sente fuori luogo. Qui infatti non conosce nessuno e suo padre, un poliziotto che detesta Spider-Man, non lo aiuta mettendolo in imbarazzo. Miles si rifugia dallo zio, che asseconda invece la sua passione da street artist, ma durante una escursione nei sotterranei di New York Miles viene morso da un ragno radioattivo. Il giorno dopo, sconvolto da sorprendenti poteri che somigliano a quelli di Spider-Man, torna a cercare il ragno e finisce per assistere a uno scontro tra l''eroe e vari villain, durante il quale un esperimento per aprire un varco dimensionale ha effetti imprevisti. Presto Miles scoprirà che non c''è un solo Uomo Ragno!');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (185, 'en', 'Spider-Man: Into the Spider-Verse', 'Struggling to find his place in the world while juggling school and family, Brooklyn teenager Miles Morales is unexpectedly bitten by a radioactive spider and develops unfathomable powers just like the one and only Spider-Man. While wrestling with the implications of his new abilities, Miles discovers a super collider created by the madman Wilson "Kingpin" Fisk, causing others from across the Spider-Verse to be inadvertently transported to his dimension.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (186, 'it', 'Dune - Parte due', 'Segui il mitico viaggio di Paul Atreides mentre si unisce a Chani e ai Fremen mentre è sul sentiero di guerra per vendicarsi dei cospiratori che hanno distrutto la sua famiglia. Di fronte a una scelta tra l''amore della sua vita e il destino dell''universo conosciuto, Paul si sforza di prevenire un terribile futuro che solo lui può prevedere.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (186, 'en', 'Dune: Part Two', 'Follow the mythic journey of Paul Atreides as he unites with Chani and the Fremen while on a path of revenge against the conspirators who destroyed his family. Facing a choice between the love of his life and the fate of the known universe, Paul endeavors to prevent a terrible future only he can foresee.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (187, 'it', 'Pressure - La decisione che cambiò la storia', 'Nelle 72 ore di tensione che precedono il D-Day, con il destino del mondo libero in bilico, il generale Dwight D. Eisenhower e il capitano James Stagg si trovano ad affrontare una scelta impossibile: lanciare la più grande e pericolosa invasione marittima della storia o rischiare di perdere del tutto la guerra.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (187, 'en', 'Pressure', 'In the tense 72 hours before D-Day, and the fate of the free world hanging in the balance, General Dwight D. Eisenhower and Captain James Stagg face an impossible choice—launch the largest and most dangerous seaborne invasion in history or risk losing the war altogether.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (188, 'it', 'Matrix', 'Seguendo un tatuaggio sulla spalla di una ragazza, l''hacker Neo scopre che la cosiddetta "realtà" è solo un impulso elettrico fornito al cervello degli umani da un''intelligenza artificiale. Per sopravvivere alla catastrofe l''umanità ha infatti avuto bisogno delle macchine, ma queste hanno vinto e necessitano degli uomini come fonte di energia. L''illusione in cui li fanno vivere è quindi finalizzata a "coltivarli" meglio. Nessuno è a conoscenza del tempo che è passato da quando il neurosimulatore ha assegnato una data fittizia al tempo. Solo Neo, con l''aiuto del pirata informatico Morpheus e della bella Trinity, può tentare di scoprire la verità, ma non sarà un''impresa facile.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (188, 'en', 'The Matrix', 'Set in the 22nd century, The Matrix tells the story of a computer hacker who joins a group of underground insurgents fighting the vast and powerful computers who now rule the earth.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (189, 'it', 'Sul tuo cadavere', 'Una coppia disfunzionale si reca in una baita isolata per "riconnettersi", ma ognuno ha intenzioni segrete di uccidere l''altro.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (189, 'en', 'Over Your Dead Body', 'A dysfunctional couple head to a remote cabin to "reconnect", but each has secret intentions to kill the other.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (190, 'it', 'Blade Runner 2049', 'Trent''anni dopo gli eventi del primo film, un nuovo blade runner, l''Agente K della Polizia di Los Angeles  scopre un segreto sepolto da tempo che ha il potenziale di far precipitare nel caos quello che è rimasto della società. La scoperta di K lo spinge verso la ricerca di Rick Deckard, un ex-blade runner della polizia di Los Angeles sparito nel nulla da 30 anni.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (190, 'en', 'Blade Runner 2049', 'Thirty years after the events of the first film, a new blade runner, LAPD Officer K, unearths a long-buried secret that has the potential to plunge what''s left of society into chaos. K''s discovery leads him on a quest to find Rick Deckard, a former LAPD blade runner who has been missing for 30 years.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (191, 'it', 'Il cavaliere oscuro', 'Il crimine organizzato a Gotham City ha le ore contate. Batman, il tenente Gordon, il nuovo Procuratore Distrettuale e alcuni improbabili epigoni dell''Uomo Pipistrello in imbottiture da hockey hanno dichiarato guerra ai criminali. La loro fortuna e i loro dollari, accumulati in una banca di massima sicurezza, vengono rubati da Joker, un pagliaccio sadico e mascherato che getterà la città nel disordine e nell''anarchia. Riempite le tasche di lame, polvere da sparo e lanugine, Joker sfiderà il cavaliere oscuro di Bruce Wayne e rivelerà il lato oscuro di Harvey Dent, l''eroe procuratore che applica la giustizia e agisce a volto scoperto.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (191, 'en', 'The Dark Knight', 'Batman raises the stakes in his war on crime. With the help of Lt. Jim Gordon and District Attorney Harvey Dent, Batman sets out to dismantle the remaining criminal organizations that plague the streets. The partnership proves to be effective, but they soon find themselves prey to a reign of chaos unleashed by a rising criminal mastermind known to the terrified citizens of Gotham as the Joker.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (192, 'it', 'Parasite', 'Tutta la famiglia di Ki-taek è senza lavoro. Ki-taek è particolarmente interessata allo stile di vita della ricchissima famiglia Park. Un giorno, suo figlio riesce a farsi assumere dai Park e le due famiglie si ritrovano così intrecciate da una serie di eventi incontrollabili.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (192, 'en', 'Parasite', 'All unemployed, Ki-taek''s family takes peculiar interest in the wealthy and glamorous Parks for their livelihood until they get entangled in an unexpected incident.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (193, 'it', 'F1: Il film', 'La leggenda delle corse automobilistiche Sonny Hayes viene convinto a uscire dal ritiro per guidare un team di Formula 1 in difficoltà e fare da mentore a un giovane pilota promettente, mentre insegue un''altra possibilità di gloria.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (193, 'en', 'F1', 'Racing legend Sonny Hayes is coaxed out of retirement to lead a struggling Formula 1 team—and mentor a young hotshot driver—while chasing one more chance at glory.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (194, 'it', 'Avengers: Endgame', 'In seguito alle azioni di Thanos nel precedente Avengers: Infinity War la popolazione dell''intero universo è stata dimezzata e tra i caduti c''è stato anche Nick Fury. Ma prima di morire questi è riuscito a lanciare un messaggio nello spazio alla potentissima Capitan Marvel, che tornata sulla Terra e di fronte a un gruppo di Avengers afflitto dalla sconfitta e dal lutto, vuole prendere le cose in mano. Quello che ha fatto Thanos però non si può risolvere con la semplice superforza e i colpi di energia...');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (194, 'en', 'Avengers: Endgame', 'After the devastating events of Avengers: Infinity War, the universe is in ruins due to the efforts of the Mad Titan, Thanos. With the help of remaining allies, the Avengers must assemble once more in order to undo Thanos'' actions and restore order to the universe once and for all, no matter what consequences may be in store.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (195, 'it', 'Il Signore degli Anelli - Il ritorno del re', 'Le forze di Sauron hanno attaccato la capitale di Gondor, Minas Tirith, nel suo assedio finale contro l''umanità. Tenuto da un debole sovrintendente, quello che una volta era un fastoso regno non ha mai avuto così bisogno del proprio re. Mentre Gandalf tenta disperatamente di spingere lo smembrato esercito di Gondor ad agire, Thèoden si unisce ai guerrieri di Rohan per combattere assieme a loro. Pieno di coraggio e di appassionata lealtà, l''esercito degli umani non riesce però a tener testa alle numerosissime legioni nemiche che giungono su tutto il regno. Ogni vittoria è accompagnata da un grande sacrificio. Malgrado le numerose perdite, la Compagnia si lancia verso la più grande battaglia mai affrontata, unita dall''unico scopo di riuscire a tenere Sauron distratto e dare a Frodo una occasione per portare a termine la sua spedizione...');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (195, 'en', 'The Lord of the Rings: The Return of the King', 'As armies mass for a final battle that will decide the fate of the world--and powerful, ancient forces of Light and Dark compete to determine the outcome--one member of the Fellowship of the Ring is revealed as the noble heir to the throne of the Kings of Men. Yet, the sole hope for triumph over evil lies with a brave hobbit, Frodo, who, accompanied by his loyal friend Sam and the hideous, wretched Gollum, ventures deep into the very dark heart of Mordor on his seemingly impossible quest to destroy the Ring of Power.​');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (196, 'it', 'Your Name.', 'Mitsuha è una studentessa che vive in una piccola città rurale e desidera trasferirsi a Tokyo, nella grande metropoli dove ogni sogno si può realizzare. Taki è uno studente di liceo che vive proprio a Tokyo, ha un lavoro part-time in un ristorante italiano, ma vorrebbe lavorare nel campo dell’arte o dell’architettura. Una notte, Mitsuha sogna di essere un giovane uomo, si ritrova in una stanza che non conosce, ha nuovi amici e lo skyline di Tokyo si apre dinnanzi al suo sguardo. Nello stesso momento Taki sogna di essere una ragazzina che vive in una piccola città di montagna che non ha mai visitato. Ma quale sarà il segreto che si cela dietro questi strani sogni incrociati?');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (196, 'en', 'Your Name.', 'High schoolers Mitsuha and Taki are complete strangers living separate lives. But one night, they suddenly switch places. Mitsuha wakes up in Taki’s body, and he in hers. This bizarre occurrence continues to happen randomly, and the two must adjust their lives around each other.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (197, 'it', 'La battaglia di Hacksaw Ridge', 'Nel film viene raccontata  la storia vera di Desmond Doss.INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (197, 'en', 'Hacksaw Ridge', 'WWII American Army Medic Desmond T. Doss, who served during the Battle of Okinawa, refuses to kill people and becomes the first Conscientious Objector in American history to receive the Congressional Medal of Honor.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (198, 'it', 'La città incantata', 'La piccola Chihiro non sopporta l''idea di traslocare e di perdere i propri amici, ma non può far niente per impedirlo. Proprio quando la famiglia è in viaggio verso la nuova casa, il padre imbocca una strada sterrata che termina davanti a un tunnel misterioso. I genitori sceglieranno di attraversarlo nonostante le rimostranze di Chihiro, per giungere a un parco dei divertimenti abbandonato, almeno apparentemente.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (198, 'en', 'Spirited Away', 'A young girl, Chihiro, becomes trapped in a strange new world of spirits. When her parents undergo a mysterious transformation, she must call upon the courage she never knew she had to free her family.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (199, 'it', 'Contrattempo', 'Dopo essersi svegliato a fianco del cadavere dell''amante, un giovane uomo d''affari ingaggia un''avvocatessa per capire in che modo è finito tra gli indagati di omicidio.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (199, 'en', 'The Invisible Guest', 'Barcelona, Spain. Adrián Doria, a young and successful businessman accused of murder, meets one night with Virginia Goodman, an expert interrogation lawyer, in order to devise a defense strategy.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (200, 'it', 'The Batman', 'Quando un killer prende di mira l’élite di Gotham con una serie di malvagi stratagemmi, una scia di indizi criptici spinge il più grande detective del mondo a indagare nei bassifondi, incontrando personaggi come Selina Kyle alias Catwoman, Oswald Cobblepot alias il Pinguino, Carmine Falcone e Edward Nashton alias l’Enigmista. Mentre le prove iniziano a condurlo più vicino alla soluzione e la portata dei piani del malfattore diventa chiara, Batman deve stringere nuove alleanze, smascherare il colpevole e rendere giustizia all’abuso di potere e alla corruzione che da tempo affliggono Gotham City.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (200, 'en', 'The Batman', 'In his second year of fighting crime, Batman uncovers corruption in Gotham City that connects to his own family while facing a serial killer known as the Riddler.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (201, 'it', 'Marty Supreme', 'Marty Mauser (Timothée Chalamet) è un venditore di scarpe con un’irrefrenabile ossessione per il ping pong che si muove nella New York degli anni ’50 fra truffe, scommesse, passioni proibite e sogni di gloria. Un’esistenza rocambolesca per un personaggio larger than life, eccentrico e ambiziosissimo, smodato e leggendario.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (201, 'en', 'Marty Supreme', 'Marty Mauser, a young man with a dream no one respects, goes to hell and back in pursuit of greatness.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (202, 'it', 'Il Signore degli Anelli - La Compagnia dell''Anello', 'Bilbo Baggins ha deciso di celebrare il suo centoundicesimo compleanno in maniera molto particolare;alla fine della festa, abbandona parenti, amici, conoscenti e il suo affezionato nipote Frodo, cui lascia ogni cosa. Lo stregone Gandalf insiste perché lo hobbit lasci a Frodo anche il suo anello magico, su cui intende tenere un occhio vigile e fare alcune ricerche, perché potrebbe celare un mistero più inquietante di quanto non sembri. E così è; quello di Bilbo è l''Unico Anello, l''Anello per domarli, il cuore del potere del malefico Signore Oscuro Sauron, che sta tornando a tessere le sue trame di conquista e distruzione. Per impedirgli di vedere realizzato il suo sanguinoso disegno, l''anello dovrà essere distrutto, cosa possibile soltanto nella fornace di Monte Fato, dove Sauron, secoli prima, lo forgiò.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (202, 'en', 'The Lord of the Rings: The Fellowship of the Ring', 'Young hobbit Frodo Baggins, after inheriting a mysterious ring from his uncle Bilbo, must leave his home in order to keep it from falling into the hands of its evil creator. Along the way, a fellowship is formed to protect the ringbearer and make sure that the ring arrives at its final destination: Mt. Doom, the only place where it can be destroyed.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (203, 'it', 'Top Gun: Maverick', 'Dopo più di trent’anni di servizio nella Marina, il capitano Pete “Maverick” Mitchell si ritrova a essere quello che sognava, un pilota collaudatore che può spingersi oltre ogni limite, schivando l’avanzamento di carriera che metterebbe un freno alla sua libertà. Quando viene richiamato a addestrare i migliori allievi Top Gun per una missione di altissima specializzazione, Maverick incontra il tenente Bradley Bradshaw, nome in codice “Rooster”, figlio del compianto “Goose”. Alle prese con un futuro incerto e con i fantasmi del passato, Maverick deve confrontarsi con le sue paure più profonde, fino alla missione che richiederà il sacrificio ultimo di quelli che sceglieranno di parteciparvi.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (203, 'en', 'Top Gun: Maverick', 'After more than thirty years of service as one of the Navy’s top aviators, and dodging the advancement in rank that would ground him, Pete “Maverick” Mitchell finds himself training a detachment of TOP GUN graduates for a specialized mission the likes of which no living pilot has ever seen.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (204, 'it', 'Hokum', 'Quando lo scrittore Ohm Bauman si ritira in una locanda isolata per spargere le ceneri dei suoi genitori, viene ossessionato dai racconti di una strega che infesta la suite nuziale. Visioni inquietanti e una scioccante scomparsa lo costringono a confrontarsi con gli angoli oscuri del suo passato.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (204, 'en', 'Hokum', 'When novelist Ohm Bauman retreats to a remote inn to scatter his parents'' ashes, he is consumed by tales of a witch haunting the honeymoon suite. Disturbing visions and a shocking disappearance forces him to confront dark corners of his past.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (205, 'it', 'Monsters & Co.', 'L''adorabile Sulley e il suo sprazzante spalla Mike Wazowski sono la squadra di paura più importante di Monsters, Inc., la fabbrica di elaborazione delle urla a Monstropolis. Quando una bambina di nome Boo entra nel loro mondo, sono i mostri a spaventarsi da morire, e spetta a Sulley e Mike tenerla nascosta e riportarla a casa.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (205, 'en', 'Monsters, Inc.', 'Lovable Sulley and his wisecracking sidekick Mike Wazowski are the top scare team at Monsters, Inc., the scream-processing factory in Monstropolis. When a little girl named Boo wanders into their world, it''s the monsters who are scared silly, and it''s up to Sulley and Mike to keep her out of sight and get her back home.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (206, 'it', 'Toy Story 3 - La grande fuga', 'Andy è in partenza per il college, sta svuotando la sua stanza e la madre lo obbliga a scegliere che fare dei vecchi giocattoli. Loro, i giocattoli, già conoscono il proprio destino, da anni Andy non gioca più come lo vediamo fare nella fenomenale sequenza d''apertura (un gioiello di racconto caotico infantile), volubili come sono però rimangono offesi dal trattamento riservatogli e quando un malinteso li fa finire nello scatolone destinato all''asilo di Sunnyside prendono l''evento di buon grado. Solo Woody, testardo, irriducibile e affezionato, continua a credere che il loro posto sia con il padrone. Gli altri lo capiranno quando scopriranno come in realtà Sunnyside sia una prigione dalla quale è impossibile evadere, gestita con pugno di ferro da una congrega di giocattoli feriti dall''abbandono dei propri padroni.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (206, 'en', 'Toy Story 3', 'Woody, Buzz, and the rest of Andy''s toys haven''t been played with in years. With Andy about to go to college, the gang find themselves accidentally left at a nefarious day care center. The toys must band together to escape and return home to Andy.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (207, 'it', 'Shaolin Soccer', 'Un maestro dell''antica arte Shaolin incontra un ex campione di calcio caduto in disgrazia e insieme decidono di applicare le arti marziali al gioco del calcio. Insieme ad altri esperti Shaolin formeranno una squadra e parteciperanno ad un torneo molto seguito.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (207, 'en', 'Shaolin Soccer', 'A young Shaolin follower reunites with his discouraged brothers to form a soccer team using their martial art skills to their advantage.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (208, 'it', 'Il diavolo veste Prada', 'Dopo essersi laureata con successo nella cittadina di provincia nella quale ha sempre vissuto, Andy si trasferisce a New York dove riesce ad essere assunta come assistente di Miranda Priestly, direttrice di Runaway, rivista di moda per eccellenza, che detta legge anche agli stilisti. I modi dispotici di Miranda e la mancanza di feeling con le ambiziosissime colleghe impongono ad Andy di cambiare se stessa tanto nell''aspetto, quanto nell''animo, per poter sopravvivere alla giungla dell''ambiente di lavoro. Pian piano conquista la fiducia di Miranda, a scapito delle amicizie e dell''amore...');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (208, 'en', 'The Devil Wears Prada', 'A young woman from the Midwest gets more than she bargained for when she moves to New York to become a writer and ends up as the assistant to the tyrannical, larger-than-life editor-in-chief of a major fashion magazine.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (209, 'it', 'Real Steel', 'In un futuro non troppo lontano il pugilato non è più una questione umana, a combattere sono dei robot manovrati dai loro tecnici. Com risultato gli incontri sono molto più efferati e di successo. Un ex-pugile caduto in disgrazia, e ora condannato a far combattere robot scassati in incontri di bassa lega, viene forzatamente riconciliato con il figlio di 11 anni dopo la morte della madre che lo aveva in affido. Con lui troverà e rimetterà in sesto un modello vecchissimo di robot-pugile che si rivelerà un''arma formidabile per farsi strada nel mondo della boxe robotica e per riunire padre e figlio alla luce di una passione comune.');
INSERT INTO "MovieTranslation" ("Movie_ID", "LanguageCode", "Title", "Story") VALUES (209, 'en', 'Real Steel', 'Charlie Kenton is a washed-up fighter who retired from the ring when robots took over the sport. After his robot is trashed, he reluctantly teams up with his estranged son to rebuild and train an unlikely contender.');
