INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (4, 'it', 'Dune - Parte Due è ora disponibile in 4K UHD', 'Il capolavoro di fantascienza di Denis Villeneuve arriva nei nostri punti vendita in edizione 4K UHD con contenuti speciali dietro le quinte.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (4, 'en', 'Dune: Part Two is now available in 4K UHD', 'Denis Villeneuve''s sci-fi masterpiece arrives in our stores in a 4K UHD edition with special behind-the-scenes content.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (5, 'it', 'Oppenheimer: l''edizione speciale Blu-ray con contenuti extra', 'Il film premio Oscar di Christopher Nolan torna disponibile in un''edizione Blu-ray arricchita da interviste esclusive e scene tagliate.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (5, 'en', 'Oppenheimer: special Blu-ray edition with extra content', 'Christopher Nolan''s Oscar-winning film returns in a Blu-ray edition enriched with exclusive interviews and deleted scenes.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (6, 'it', 'The Batman torna disponibile in edizione Steelbook 4K', 'Il thriller diretto da Matt Reeves è di nuovo disponibile in un''esclusiva Steelbook da collezione in 4K UHD.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (6, 'en', 'The Batman is back in a 4K Steelbook edition', 'Matt Reeves'' thriller is available again in an exclusive collector''s 4K UHD Steelbook.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (7, 'it', 'Top Gun: Maverick, sconto del 15% questa settimana', 'Per una settimana, il sequel diretto da Joseph Kosinski è disponibile con il 15% di sconto in tutti i formati.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (7, 'en', 'Top Gun: Maverick, 15% off this week', 'For one week, Joseph Kosinski''s sequel is available with a 15% discount across all formats.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (8, 'it', 'Avatar: La Via dell''Acqua in un cofanetto speciale', 'Il visionario sequel di James Cameron arriva in un cofanetto da collezione con poster esclusivo incluso.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (8, 'en', 'Avatar: The Way of Water in a special box set', 'James Cameron''s visionary sequel arrives in a collector''s box set including an exclusive poster.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (9, 'it', 'Spider-Man: No Way Home in edizione da collezione', 'Il film di Jon Watts con Tom Holland arriva in una nuova edizione da collezione con card litografiche esclusive.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (9, 'en', 'Spider-Man: No Way Home in a collector''s edition', 'Jon Watts'' film starring Tom Holland arrives in a new collector''s edition with exclusive lithograph cards.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (10, 'it', 'Il Padrino: il capolavoro di Coppola torna in 4K', 'Per festeggiare l''anniversario, il capolavoro di Francis Ford Coppola torna disponibile in un restauro 4K UHD.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (10, 'en', 'The Godfather: Coppola''s masterpiece returns in 4K', 'To celebrate its anniversary, Francis Ford Coppola''s masterpiece is back in a restored 4K UHD edition.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (11, 'it', 'Interstellar: nuova ristampa in Blu-ray da oggi', 'Il viaggio interstellare diretto da Christopher Nolan è di nuovo disponibile in una nuova ristampa Blu-ray.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (11, 'en', 'Interstellar: new Blu-ray reprint out today', 'Christopher Nolan''s interstellar journey is available again in a new Blu-ray reprint.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (12, 'it', 'Zootropolis 2 arriva nei nostri punti vendita', 'Il nuovo capitolo animato diretto da Jared Bush e Byron Howard è ora disponibile in DVD e Blu-ray per tutta la famiglia.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (12, 'en', 'Zootopia 2 arrives in our stores', 'The new animated chapter directed by Jared Bush and Byron Howard is now available on DVD and Blu-ray for the whole family.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (13, 'it', 'Avengers: Endgame nel cofanetto Saga Completa', 'L''epico finale diretto dai fratelli Russo è ora incluso nel nuovo cofanetto da collezione con l''intera saga degli Avengers.');
INSERT INTO "NewsTranslation" ("News_ID", "LanguageCode", "Title", "Text") VALUES (13, 'en', 'Avengers: Endgame in the Complete Saga box set', 'The epic finale directed by the Russo brothers is now included in the new collector''s box set featuring the entire Avengers saga.');
