INSERT INTO "Review" ("ReviewId", "MovieId", "UserId", "Rating", "Comment", "CreatedAt") VALUES (6, 107, 5, 5, 'Un capolavoro di fantascienza, trama avvincente dall''inizio alla fine.', '2026-06-01T00:00:00');
INSERT INTO "Review" ("ReviewId", "MovieId", "UserId", "Rating", "Comment", "CreatedAt") VALUES (7, 107, 6, 4, 'Ottima regia, un po'' complesso da seguire ma vale assolutamente la visione.', '2026-06-04T00:00:00');
INSERT INTO "Review" ("ReviewId", "MovieId", "UserId", "Rating", "Comment", "CreatedAt") VALUES (8, 108, 7, 5, 'Musiche fantastiche e fotografia superba, uno dei migliori musical recenti.', '2026-06-07T00:00:00');
INSERT INTO "Review" ("ReviewId", "MovieId", "UserId", "Rating", "Comment", "CreatedAt") VALUES (9, 111, 8, 4, 'Perfetto da guardare con i bambini, colonna sonora davvero orecchiabile.', '2026-06-10T00:00:00');
INSERT INTO "Review" ("ReviewId", "MovieId", "UserId", "Rating", "Comment", "CreatedAt") VALUES (10, 112, 9, 4, 'Nostalgico e divertente, un degno seguito della saga.', '2026-06-13T00:00:00');
INSERT INTO "Review" ("ReviewId", "MovieId", "UserId", "Rating", "Comment", "CreatedAt") VALUES (11, 115, 10, 5, 'Avventura epica, effetti speciali notevoli e ritmo serrato.', '2026-06-16T00:00:00');
INSERT INTO "Review" ("ReviewId", "MovieId", "UserId", "Rating", "Comment", "CreatedAt") VALUES (12, 117, 11, 3, 'Storia interessante ma un po'' lenta a tratti, mi aspettavo di più.', '2026-06-19T00:00:00');
INSERT INTO "Review" ("ReviewId", "MovieId", "UserId", "Rating", "Comment", "CreatedAt") VALUES (13, 119, 12, 4, 'Seguito riuscito, cast azzeccato e dialoghi brillanti.', '2026-06-22T00:00:00');
INSERT INTO "Review" ("ReviewId", "MovieId", "UserId", "Rating", "Comment", "CreatedAt") VALUES (14, 127, 5, 4, 'Adrenalina pura per i fan del franchise, combattimenti spettacolari.', '2026-06-25T00:00:00');
INSERT INTO "Review" ("ReviewId", "MovieId", "UserId", "Rating", "Comment", "CreatedAt") VALUES (15, 121, 6, 3, 'Carino ma poco originale rispetto ad altri film del genere.', '2026-06-28T00:00:00');
